    category: `Company Specific`,
    heroImage: `https://images.unsplash.com/photo-1508514177221-188b1cf16e9d?w=1200&q=80`,
    heroAlt: `Sunnova Bankruptcy: What This Means for Your Solar Loan and Lease`,
